import{_ as s,W as o,X as r,Z as e,$ as a,a0 as t,Y as i,C as l}from"./framework-b9c734bc.js";const d={},c=i('<h1 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h1><p>使用webdav协议将阿里云盘挂载本地，可以让阿里云盘变身为webdav协议的文件服务器。基于此，可以把阿里云盘挂载为Windows、Linux、Mac系统的磁盘，可以通过NAS系统做文件管理或文件同步和更多玩法，本篇主要是针对Mac系统的教程。</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227143540198.png" alt="挂载成功图片" tabindex="0" loading="lazy"><figcaption>挂载成功图片</figcaption></figure><h1 id="准备工作" tabindex="-1"><a class="header-anchor" href="#准备工作" aria-hidden="true">#</a> 准备工作</h1>',4),h=e("li",null,[e("p",null,"Java环境"),e("p",null,[a("本次使用Jar包运行，因此需要Java环境，如何部署Java环境此处不进行赘述，网上很多教程，打开终端使用"),e("code",null,"java -version"),a("命令确认是否有Java环境。")]),e("figure",null,[e("img",{src:"https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227144357075.png",alt:"Java环境确认",tabindex:"0",loading:"lazy"}),e("figcaption",null,"Java环境确认")])],-1),p=e("p",null,[e("code",null,"webdav-aliyundriver")],-1),u={href:"https://github.com/zxbu/webdav-aliyundriver/releases/latest",target:"_blank",rel:"noopener noreferrer"},g=e("code",null,"readme.md",-1),m=e("figure",null,[e("img",{src:"https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227144905005.png",alt:"下载页面",tabindex:"0",loading:"lazy"}),e("figcaption",null,"下载页面")],-1),b=e("blockquote",null,[e("p",null,[a("建议自己下载源码编译，以获得最新代码，如果是下载的源码，建议打开后，"),e("a",{href:"#%E6%9B%B4%E6%94%B9%E6%9C%AC%E5%9C%B0%E6%96%87%E4%BB%B6%E5%A4%B9"},"对本地文件夹进行修改"),a("。")])],-1),v=e("p",null,"CloudMounter",-1),_={href:"https://www.macwk.com/soft/cloudmounter",target:"_blank",rel:"noopener noreferrer"},f=e("img",{src:"https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227152459255.png",alt:"image-20211227152459255",style:{zoom:"50%"}},null,-1),k=e("h1",{id:"开始配置",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#开始配置","aria-hidden":"true"},"#"),a(" 开始配置")],-1),y=e("h2",{id:"获取refreshtoken",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#获取refreshtoken","aria-hidden":"true"},"#"),a(" 获取refreshToken")],-1),x={href:"https://www.aliyundrive.com/drive/",target:"_blank",rel:"noopener noreferrer"},M=e("li",null,[a("登录成功后，按F12打开开发者工具，点击Application，点击Local Storage，点击 Local Storage下的 "),e("code",null,"https://www.aliyundrive.com/"),a("，点击右边的token，此时可以看到里面的数据，其中就有refresh_token，把其值复制出来即可。（格式为小写字母和数字，不要复制双引号。例子：ca6bf2175d73as2188efg81f87e55f11）")],-1),j=e("li",null,[a("第二步有点繁琐，大家结合下面的截图就看懂了 "),e("img",{src:"https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/119246278-e6760880-bbb2-11eb-877c-aca16cf75d89.png",alt:"image",loading:"lazy"})],-1),w={href:"https://github.com/zxbu/webdav-aliyundrive",target:"_blank",rel:"noopener noreferrer"},q=e("code",null,"readme.md",-1),z=i(`<h2 id="运行" tabindex="-1"><a class="header-anchor" href="#运行" aria-hidden="true">#</a> 运行</h2><ol><li><p>找到下载或打包好的jar包，打开终端，进入jar包位置的路径，然后使用下面的命令运行项目。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 这里的webdav.jar就是下载或打包好的jar包名称，不一致修改为一致即可</span>
<span class="token function">java</span> <span class="token parameter variable">-jar</span> webdav.jar --aliyundrive.refresh-token<span class="token operator">=</span><span class="token string">&quot;your refreshToken&quot;</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227151921835.png" alt="image-20211227151921835" tabindex="0" loading="lazy"><figcaption>image-20211227151921835</figcaption></figure><ol start="2"><li><p>打开浏览器查看是否正常</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227152154666.png" alt="image-20211227152154666" tabindex="0" loading="lazy"><figcaption>image-20211227152154666</figcaption></figure></li></ol><blockquote><p>第一次打开会要求输入用户名和密码，默认都是admin。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227165530623.png" alt="image-20211227165530623" style="zoom:50%;"></blockquote><h2 id="用cloudmounter连接" tabindex="-1"><a class="header-anchor" href="#用cloudmounter连接" aria-hidden="true">#</a> 用CloudMounter连接</h2><p>打开CloudMounter，选择WebDAV，然后连接到阿里云盘，再打开访达页面就和我最开始的一样了。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227152632386.png" alt="image-20211227152632386" style="zoom:50%;"><blockquote><p>注意运行项目的终端窗口一直不要关闭，另外图中的用户密码默认也都是admin。</p></blockquote><h1 id="优化" tabindex="-1"><a class="header-anchor" href="#优化" aria-hidden="true">#</a> 优化</h1><h2 id="开机自启动" tabindex="-1"><a class="header-anchor" href="#开机自启动" aria-hidden="true">#</a> 开机自启动</h2><p>要一直保持运行项目的终端窗口不能关闭，且不能开机自启动显然不够优雅，所以可以使用脚本命令设置为开机自启动。</p><ol><li><p>建立脚本文件：<code>webdav.sh</code>；</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 进入到jar包所在文件夹位置</span>
<span class="token builtin class-name">cd</span> /Users/hk/Documents/webdav 
<span class="token comment"># &quot;nohup XXX &amp;&quot;可以让你的命令在后台持续运行，终端关闭也没问题</span>
<span class="token function">nohup</span> <span class="token function">java</span> <span class="token parameter variable">-jar</span> webdav.jar --aliyundrive.refresh-token<span class="token operator">=</span><span class="token string">&quot;dca09cb094cd487ba5f88ef5b5848fb3&quot;</span> <span class="token operator">&amp;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>设置开机自启动。</p><p>首先打开&quot;系统偏好设置--&gt;用户与群组--&gt;登录项&quot;，然后点击<code>+</code>，把<code>webdav.sh</code>文件加入到登录项即可。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227153748641.png" alt="image-20211227153748641" style="zoom:50%;"></li></ol><h2 id="关闭挂载服务" tabindex="-1"><a class="header-anchor" href="#关闭挂载服务" aria-hidden="true">#</a> 关闭挂载服务</h2><p>我们设置了开机自启动，当对源码进行更改后，需要停止服务，重新打包运行，那么就要先把项目进程关闭，可按以下操作。</p><h3 id="方法一" tabindex="-1"><a class="header-anchor" href="#方法一" aria-hidden="true">#</a> 方法一</h3><ol><li><p>打开终端，查找使用8080端口的进程名有哪些。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 查找使用8080端口的进程</span>
<span class="token function">lsof</span> <span class="token parameter variable">-i</span> tcP:8080 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>找到其中java进程的pid，然后杀掉</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 杀掉 583 进程</span>
<span class="token function">kill</span> <span class="token number">583</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227154259947.png" alt="image-20211227154259947" tabindex="0" loading="lazy"><figcaption>image-20211227154259947</figcaption></figure><blockquote><p>对于shell语句不熟悉的，可以把查找进程这条命令也加入到<code>webdav.sh</code>中，然后在该脚本同目录下的<code>nohup.out</code>文件中会进行记录，这样需要停止服务的时候进去看下是那个进程就可以了。</p></blockquote><h3 id="方法二" tabindex="-1"><a class="header-anchor" href="#方法二" aria-hidden="true">#</a> 方法二</h3><p>还有个更简单的方法，打开活动监视器，然后搜索java就可以找到对应的进程并结束，我用上面的方法最主要的原因是一开始不知道该项目运行后的进程叫啥。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227204433101.png" alt="image-20211227204433101" style="zoom:50%;"><h2 id="更改本地文件夹" tabindex="-1"><a class="header-anchor" href="#更改本地文件夹" aria-hidden="true">#</a> 更改本地文件夹</h2><p>改一下这个本地文件夹，默认是在<code>/etc/</code>下，在Mac系统中可能会有权限问题。</p><ol><li>更改源码</li></ol><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227145914311.png" alt="image-20211227145914311" tabindex="0" loading="lazy"><figcaption>image-20211227145914311</figcaption></figure><ol start="2"><li><p>打包</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227150052118.png" alt="image-20211227150052118" style="zoom:50%;"></li></ol><blockquote><p>推荐有Java项目开发经验的搞。</p></blockquote><h2 id="更改端口号" tabindex="-1"><a class="header-anchor" href="#更改端口号" aria-hidden="true">#</a> 更改端口号</h2><p>一直在后台开启会占用8080默认端口号，我们在开发别的项目时，就很不方便，所以最好把端口号进行修改。</p><h3 id="方法一-1" tabindex="-1"><a class="header-anchor" href="#方法一-1" aria-hidden="true">#</a> 方法一</h3><p>通过在<code>application.properties</code>配置文件中添加一行<code>server.port=8000</code>，修改成我们想要的端口号即可。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227170106038.png" alt="修改端口号" style="zoom:50%;"><blockquote><p>同时在这里也可以对登录的用户名和密码进行修改。</p></blockquote><h3 id="方法二-1" tabindex="-1"><a class="header-anchor" href="#方法二-1" aria-hidden="true">#</a> 方法二</h3><p>更简单的方法，直接在启动项目时，将<code>server.port</code>拼在后面</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">java</span> <span class="token parameter variable">-jar</span> webdav.jar --aliyundrive.refresh-token<span class="token operator">=</span><span class="token string">&quot;dca09cb094cd487ba5f88ef5b5848fb3&quot;</span> <span class="token parameter variable">--server.port</span><span class="token operator">=</span><span class="token number">8010</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20211227202957434.png" alt="image-20211227202957434" style="zoom:50%;"><h2 id="自动化" tabindex="-1"><a class="header-anchor" href="#自动化" aria-hidden="true">#</a> 自动化</h2><h3 id="退出终端" tabindex="-1"><a class="header-anchor" href="#退出终端" aria-hidden="true">#</a> 退出终端</h3><p>虽然我们已经优化为<a href="#%E5%BC%80%E6%9C%BA%E8%87%AA%E5%90%AF%E5%8A%A8">开机自启动</a>了，但是开机后的终端运行<code>webdav.sh</code>脚本后，并不会关闭终端窗口并退出软件。因此这里我使用了<code>Keyboard Maestro</code>软件（以下简称KM）添加了自动化操作来关闭终端。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20220113130656853.png" alt="image-20220113130656853" style="zoom:50%;"><h3 id="挂载云盘" tabindex="-1"><a class="header-anchor" href="#挂载云盘" aria-hidden="true">#</a> 挂载云盘</h3><p>在实际使用过程中，我发现如果只是把CloudMounter设置为开机自启动，虽然在软件中设置了启动时自动挂载云盘，但实际上，因为<code>webdav.sh</code>脚本需要一定时间才能执行成功，所以会导致CloudMounter不能完成启动自动挂载云盘。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20220113132306824.png" alt="image-20220113132306824" style="zoom:50%;"><p>这里也是使用了KM软件来完成等待一段时间后，再启动CloudMounter，此时<code>webdav.sh</code>脚本也已经运行成功，所以实现了启动就挂载好云盘，不用我们再去手动挂载了。</p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Mac_aly_note/image-20220113131437548.png" alt="image-20220113131437548" style="zoom:50%;"><blockquote><p>有自动化启动CloudMounter软件，就不用设置CloudMounter自启动了，但记得要设置KM软件自启动。</p></blockquote>`,48);function C(E,A){const n=l("ExternalLinkIcon");return o(),r("div",null,[c,e("ol",null,[h,e("li",null,[p,e("p",null,[a("感谢zxbu大佬开源的项目，"),e("a",u,[a("点击下载项目"),t(n)]),a("，并阅读其中的"),g,a("对该项目进行熟悉。")]),m,b]),e("li",null,[v,e("p",null,[a("可使用WebDAV协议挂载阿里网盘，选择他主要是觉得比较好用，也可以选择其它的，"),e("a",_,[a("下载链接"),t(n)]),a("。")]),f])]),k,y,e("ol",null,[e("li",null,[a("先通过浏览器（建议chrome）打开阿里云盘官网并登录："),e("a",x,[a("https://www.aliyundrive.com/drive/"),t(n)])]),M,j]),e("blockquote",null,[e("p",null,[a("该步参考"),e("a",w,[a("项目地址"),t(n)]),q,a("中的内容。")])]),z])}const J=s(d,[["render",C],["__file","Mac-mounts-Ali-cloud-disk.html.vue"]]);export{J as default};
